import{_ as e,c as t,o as i,a1 as a}from"./chunks/framework.DDNAyvCW.js";const o="/assets/plugin.WVshtvWM.png",x=JSON.parse('{"title":"Extension Management","description":"","frontmatter":{},"headers":[],"relativePath":"docs/manage/plugin/index.md","filePath":"docs/manage/plugin/index.md"}'),s={name:"docs/manage/plugin/index.md"};function l(r,n,g,c,d,h){return i(),t("div",null,n[0]||(n[0]=[a('<h1 id="extension-management" tabindex="-1">Extension Management <a class="header-anchor" href="#extension-management" aria-label="Permalink to &quot;Extension Management&quot;">​</a></h1><p>Install and manage extensions to customize and expand Chaterm&#39;s capabilities.</p><p><img src="'+o+'" alt=""></p><h2 id="browsing-extensions" tabindex="-1">Browsing Extensions <a class="header-anchor" href="#browsing-extensions" aria-label="Permalink to &quot;Browsing Extensions&quot;">​</a></h2><ol><li>Click <strong>Extensions</strong> in the left sidebar to open the Extension Management page.</li><li>Select the <strong>Extension Marketplace</strong> tab to see all available extensions, or switch to the <strong>Installed Extensions</strong> tab to see extensions already on your system.</li><li>Use the <strong>search bar</strong> to filter extensions by keyword.</li><li>Click an extension card to view its details, including a full description, feature list, and version information.</li></ol><h2 id="installing-an-extension" tabindex="-1">Installing an Extension <a class="header-anchor" href="#installing-an-extension" aria-label="Permalink to &quot;Installing an Extension&quot;">​</a></h2><p><strong>From the Extension Marketplace</strong></p><ol><li>On the Extension Management page, browse or search for the extension you need.</li><li>Click the extension card to review its details.</li><li>Click the <strong>Install</strong> button.</li><li>Wait for the installation to complete.</li></ol><p><strong>From a Local File</strong></p><ol><li>Click the <strong>Install from File</strong> button.</li><li>Select an extension package file (<code>.chaterm</code> format) from your local machine.</li><li>Chaterm verifies and installs the extension automatically.</li></ol><div class="tip custom-block"><p class="custom-block-title">Auto-enabled After Install</p><p>Extensions are <strong>automatically enabled</strong> as soon as installation finishes. You can start using the new functionality right away, and you can manage the extension from the <strong>Installed Extensions</strong> tab.</p></div><h2 id="enabling-and-disabling-an-extension" tabindex="-1">Enabling and Disabling an Extension <a class="header-anchor" href="#enabling-and-disabling-an-extension" aria-label="Permalink to &quot;Enabling and Disabling an Extension&quot;">​</a></h2><ol><li>Go to the <strong>Installed Extensions</strong> tab.</li><li>Locate the extension you want to toggle.</li><li>Click the <strong>Enable</strong> button to activate a disabled extension, or click the <strong>Disable</strong> button to deactivate an active extension.</li><li>The change takes effect immediately -- no restart required.</li></ol><div class="warning custom-block"><p class="custom-block-title">Core Extensions</p><p>Disabling certain core extensions may break essential Chaterm functionality (for example, terminal rendering or connection handling). Only disable an extension if you are sure it is not required for your workflow.</p></div><h2 id="configuring-an-extension" tabindex="-1">Configuring an Extension <a class="header-anchor" href="#configuring-an-extension" aria-label="Permalink to &quot;Configuring an Extension&quot;">​</a></h2><p>Some extensions expose settings that let you customize their behavior:</p><ol><li>In the <strong>Installed Extensions</strong> tab, find the extension you want to configure.</li><li>Click the <strong>Configure</strong> button. A settings dialog opens.</li><li>Adjust the available options. Common configuration items include: <ul><li>Feature switches (on / off toggles)</li><li>Display options (themes, layout)</li><li>Behavior parameters (timeouts, defaults)</li><li>Integration settings (API keys, endpoints)</li></ul></li><li>Click <strong>Save</strong>. The new configuration takes effect immediately.</li></ol><p>For global extension preferences, see <a href="/docs/settings/extensions/">Extension Settings</a>.</p><h2 id="updating-an-extension" tabindex="-1">Updating an Extension <a class="header-anchor" href="#updating-an-extension" aria-label="Permalink to &quot;Updating an Extension&quot;">​</a></h2><p>When a newer version of an installed extension is available:</p><ol><li>An <strong>update badge</strong> appears next to the extension in the list.</li><li>Click the <strong>Update</strong> button to upgrade to the latest version.</li><li>Your existing configuration is preserved after the update.</li></ol><h2 id="uninstalling-an-extension" tabindex="-1">Uninstalling an Extension <a class="header-anchor" href="#uninstalling-an-extension" aria-label="Permalink to &quot;Uninstalling an Extension&quot;">​</a></h2><ol><li>In the <strong>Installed Extensions</strong> tab, locate the extension you want to remove.</li><li>Click the <strong>Uninstall</strong> button.</li><li>Confirm the action in the dialog. The extension and its data are removed from Chaterm.</li></ol>',23)]))}const m=e(s,[["render",l]]);export{x as __pageData,m as default};
